const WithHoverContent = () => {
  const [hoveredName, setHoveredName] = useState<string | null>(null);
  const [selectedNames, setSelectedNames] = useState<string[]>([]);

  return (
    <div>
      <GeoJsonEditor
        value={norwegianCoastData}
        fitBounds
        showCenterAction
        hoverContent={{
          harbor: (f) => (
            <div>
              <strong>{f.properties?.name}</strong>
              <div>Kapasitet: {f.properties?.capacity} båter</div>
            </div>
          ),
          lighthouse: (f) => (
            <div>
              <strong>{f.properties?.name}</strong>
              <div>Høyde: {f.properties?.height} m</div>
            </div>
          ),
          shipping_lane: (f) => (
            <div>
              <strong>{f.properties?.name}</strong>
              <div>Trafikk: {f.properties?.traffic}</div>
            </div>
          ),
        }}
        onHover={(feature) => setHoveredName(feature?.properties?.name ?? null)}
        onSelect={(features) =>
          setSelectedNames(
            features?.map((f) => f.properties?.name ?? "ukjent") ?? [],
          )
        }
      />
      <div
        style={{
          marginTop: 12,
          padding: 10,
          background: "#f5f5f5",
          borderRadius: 8,
          fontSize: "0.85rem",
        }}
      >
        <div>
          <strong>Hover:</strong> {hoveredName ?? "–"}
        </div>
        <div>
          <strong>Valgt:</strong>{" "}
          {selectedNames.length > 0 ? selectedNames.join(", ") : "–"}
        </div>
      </div>
    </div>
  );
};

